import { verifySession } from '@/lib/dal'
import { getTags } from '@/lib/api/documents'
import { VideoUpload } from '@/components/video-upload'

export default async function UploadPage() {
  await verifySession()
  const tags = await getTags().catch(() => [])

  return (
    <div className="px-8 py-8 max-w-3xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-stone-900">Upload Sermon</h1>
        <p className="text-stone-500 mt-1 text-sm">
          Videos are uploaded directly to S3 and processed automatically.
        </p>
      </div>

      <VideoUpload tags={tags} />
    </div>
  )
}
